import {{ Injectable }} from '@nestjs/common';
import {{ AnalyticsService }} from './models/analytics.model';
import {{ AnalyticsServiceRepository }} from './repositories/analytics.repository';

@Injectable()
export class AnalyticsServiceService {{
  constructor(
    private readonly repository: AnalyticsServiceRepository,
  ) {{}}

  async findAll(): Promise<AnalyticsService[]> {{
    return this.repository.findAll();
  }}

  async findById(id: string): Promise<AnalyticsService | null> {{
    return this.repository.findById(id);
  }}

  async create(data: Partial<AnalyticsService>): Promise<AnalyticsService> {{
    return this.repository.create(data);
  }}

  async update(id: string, data: Partial<AnalyticsService>): Promise<AnalyticsService> {{
    return this.repository.update(id, data);
  }}
}}

